    25→  for (const p of candidates) {
    26→    if (require("fs").existsSync(p)) return p;
    27→  }
    28→  return null;
    29→}
    30→
    31→function rgAvailable(): boolean {
    32→  try {
    33→    execSync("rg --version", { stdio: "pipe" });
    34→    return true;
    35→  } catch {
    36→    return false;
    37→  }
    38→}
    39→
    40→function escapeRegex(s: string): string {
    41→  return s.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
    42→}
    43→
    44→export function findDefinition(symbol: string, options: QueryOptions = {}): QueryResult[] {
    45→  const cwd = options.cwd || process.cwd();
    46→  const dbPath = options.dbPath || findDbPath(cwd);
    47→
    48→  if (dbPath) {
    49→    try {
    50→      const db = new Database(dbPath);
    51→      const stmt = db.prepare(
    52→        `SELECT s.name, s.definition, s.kind
    53→         FROM symbols s
    54→         WHERE s.name LIKE ? AND s.definition IS NOT NULL`
    55→      );
    56→      const rows = stmt.all(`%${symbol}%`) as Array<{ name: string; definition: string; kind: string }>;
    57→      db.close();
    58→
    59→      return rows
    60→        .map((r) => {
    61→          const parts = r.definition?.split(":");
    62→          if (!parts || parts.length < 2) return null;
    63→          return {
    64→            file: parts[0],
    65→            line: parseInt(parts[1], 10) || 0,
    66→            column: 0,
    67→            text: `${r.kind}: ${r.name}`,
    68→            kind: "definition" as const,
    69→          };
    70→        })
    71→        .filter((r): r is QueryResult => r !== null);
    72→    } catch {
    73→      // Fall through to grep
    74→    }
    75→  }
    76→
    77→  // Fallback: grep-based search
    78→  const pattern = `\\b${escapeRegex(symbol)}\\b`;
    79→  const cmd = rgAvailable()
    80→    ? `rg -n --type ts "^(export\\s+)?(async\\s+)?(function|const|let|class|interface)\\s+${escapeRegex(symbol)}"`
    81→    : `grep -rn "^(export\\s\+\)\?\(async\\s\+\)\?\(function\\|const\\|let\\|class\\|interface\)\\s\+${escapeRegex(symbol)}" --include="*.ts"`;
    82→
    83→  try {
    84→    const output = execSync(cmd, { cwd, encoding: "utf-8", maxBuffer: 10 * 1024 * 1024 });
    85→    return parseGrepOutput(output).map((r) => ({ ...r, kind: "definition" as const }));
    86→  } catch {
    87→    return [];
    88→  }
    89→}
    90→
    91→export function findReferences(symbol: string, options: QueryOptions = {}): QueryResult[] {
    92→  const cwd = options.cwd || process.cwd();
    93→  const pattern = `\\b${escapeRegex(symbol)}\\b`;
    94→
    95→  const cmd = rgAvailable()
    96→    ? `rg -n --type ts ${JSON.stringify(pattern)}`
    97→    : `grep -rn ${JSON.stringify(pattern)} --include="*.ts"`;
    98→
    99→  try {
   100→    const output = execSync(cmd, { cwd, encoding: "utf-8", maxBuffer: 10 * 1024 * 1024 });
   101→    return parseGrepOutput(output).map((r) => ({ ...r, kind: "reference" as const }));
   102→  } catch {
   103→    return [];
   104→  }
   105→}
   106→
   107→export function findCallers(symbol: string, options: QueryOptions = {}): QueryResult[] {
   108→  const cwd = options.cwd || process.cwd();
   109→  const pattern = `${escapeRegex(symbol)}\\s*\\(`;
   110→
   111→  const cmd = rgAvailable()
   112→    ? `rg -n --type ts ${JSON.stringify(pattern)}`
   113→    : `grep -rn ${JSON.stringify(pattern)} --include="*.ts"`;
   114→
   115→  try {
   116→    const output = execSync(cmd, { cwd, encoding: "utf-8", maxBuffer: 10 * 1024 * 1024 });
   117→    return parseGrepOutput(output).map((r) => ({ ...r, kind: "call" as const }));
   118→  } catch {
   119→    return [];
   120→  }
   121→}
   122→
   123→function parseGrepOutput(output: string): QueryResult[] {
   124→  if (!output.trim()) return [];
   125→  return output
   126→    .trim()
   127→    .split("\n")
   128→    .map((line) => {
   129→      const match = line.match(/^([^:]+):(\d+):(.*)$/);
   130→      if (!match) return null;
   131→      return {
   132→        file: match[1],
   133→        line: parseInt(match[2], 10),
   134→        column: 0,
   135→        text: match[3].trim(),
   136→        kind: "reference" as const,
   137→      };
   138→    })
   139→    .filter((r): r is QueryResult => r !== null);
   140→}
   141→

