{"role":"user","content":[{"tool_use_id":"call_4667db7655ba42aaa6d75b25","type":"tool_result","content":"     1→import { existsSync, readFileSync } from "fs";
     2→import { join, basename } from "path";
     3→import { execFile } from "child_process";
     4→import { promisify } from "util";
     5→import Database from "better-sqlite3";
     6→
     7→const execFileAsync = promisify(execFile);
     8→
     9→export type ProjectType = "typescript" | "go";
    10→
    11→export interface IndexResult {
    12→  success: boolean;
    13→  dbPath?: string;
    14→  documentCount?: number;
    15→  symbolCount?: number;
    16→  error?: string;
    17→}
    18→
    19→export function detectProjectType(projectPath: string): ProjectType | null {
    20→  if (existsSync(join(projectPath, "tsconfig.json"))) {
    21→    return "typescript";
    22→  }
    23→  if (existsSync(join(projectPath, "go.mod"))) {
    24→    return "go";
    25→  }
    26→  return null;
    27→}
    28→
    29→function indexerCommand(
    30→  projectType: ProjectType
    31→): { cmd: string; args: string[] } | null {
    32→  switch (projectType) {
    33→    case "typescript":
    34→      return { cmd: "scip-typescript", args: ["index", "--output", "index.json"] };
    35→    case "go":
    36→      return { cmd: "scip-go", args: ["index", "--output", "index.json"] };
    37→    default:
    38→      return null;
    39→  }
    40→}
    41→
    42→function createSchema(db: Database.Database): void {
    43→  db.exec(`
    44→    CREATE TABLE IF NOT EXISTS documents (
    45→      id    INTEGER PRIMARY KEY AUTOINCREMENT,
    46→      path  TEXT    NOT NULL,
    47→      hash  TEXT
    48→    );
    49→    CREATE TABLE IF NOT EXISTS symbols (
    50→      id            INTEGER PRIMARY KEY AUTOINCREMENT,
    51→      name          TEXT    NOT NULL,
    52→      kind          TEXT    NOT NULL,
    53→      definition    TEXT,
    54→      document_id   INTEGER REFERENCES documents(id) ON DELETE CASCADE
    55→    );
    56→    CREATE INDEX IF NOT EXISTS idx_symbols_name ON symbols(name);
    57→    CREATE INDEX IF NOT EXISTS idx_symbols_document ON symbols(document_id);
    58→  `);
    59→}
    60→
    61→interface ScipSymbol {
    62→  name: string;
    63→  kind: string;
    64→  definition?: string;
    65→  documentPath?: string;
    66→}
    67→
    68→function parseScipOutput(scipPath: string): ScipSymbol[] {
    69→  if (!existsSync(scipPath)) return [];
    70→
    71→  const raw = readFileSync(scipPath, "utf-8");
    72→  try {
    73→    const doc = JSON.parse(raw);
    74→    return extractSymbols(doc);
    75→  } catch {
    76→    console.error("Warning: could not parse SCIP output");
    77→    return [];
    78→  }
    79→}
    80→
    81→function extractSymbols(doc: Record<string, unknown>): ScipSymbol[] {
    82→  const symbols: ScipSymbol[] = [];
    83→  const externalSymbols: Record<string, unknown> =
    84→    (doc.external_symbols as Record<string, unknown>) ?? {};
    85→  const internalSymbols: Record<string, unknown> =
    86→    (doc.internal_symbols as Record<string, unknown>) ?? {};
    87→  const documents: Record<string, unknown> =
    88→    (doc.documents as Record<string, unknown>) ?? {};
    89→
    90→  const allSymbols = { ...externalSymbols, ...internalSymbols };
    91→  const pathByDocId: Record<string, string> = {};
    92→
    93→  for (const [docId, docData] of Object.entries(documents)) {
    94→    const relativePath = (docData as Record<string, unknown>).relative_path as
    95→      | string
    96→      | undefined;
    97→    if (relativePath) pathByDocId[docId] = relativePath;
    98→  }
    99→
   100→  for (const [symbolKey, symData] of Object.entries(allSymbols)) {
   101→    const sym = symData as Record<string, unknown>;
   102→    const relationships = sym.relationships as Record<string, unknown> | undefined;
   103→    const defRef = relationships?.definition_reference as
   104→      | Record<string, unknown>
   105→      | undefined;
   106→    const docRef = defRef?.document as string | undefined;
   107→
   108→    symbols.push({
   109→      name: symbolKey,
   110→      kind: (sym.kind as string) ?? "unknown",
   111→      definition: defRef
   112→        ? `${pathByDocId[docRef ?? ""] ?? docRef}:${defRef.start_line ?? 0}`
   113→        : undefined,
   114→      documentPath: docRef ? pathByDocId[docRef] : undefined,
   115→    });
   116→  }
   117→
   118→  return symbols;
   119→}
   120→
   121→export async function buildIndex(
   122→  projectPath: string,
   123→  projectType: ProjectType
   124→): Promise<IndexResult> {
   125→  const spec = indexerCommand(projectType);
   126→  if (!spec) {
   127→    return { success: false, error: `unsupported project type: ${projectType}` };
   128→  }
   129→
   130→  try {
   131→    await execFileAsync(spec.cmd, spec.args, { cwd: projectPath });
   132→  } catch (err) {
   133→    const msg = err instanceof Error ? err.message : String(err);
   134→    return { success: false, error: `indexer failed: ${msg}` };
   135→  }
   136→
   137→  const scipPath = join(projectPath, "index.json");
   138→  if (!existsSync(scipPath)) {
   139→    return {
   140→      success: false,
   141→      error: `indexer produced no output at ${scipPath}`,
   142→    };
   143→  }
   144→
   145→  const symbols = parseScipOutput(scipPath);
   146→  const dbPath = join(projectPath, `${basename(projectPath)}.fg-index.db`);
   147→
   148→  const db = new Database(dbPath);
   149→  try {
   150→    createSchema(db);
   151→
   152→    const insertDoc = db.prepare(
   153→      "INSERT INTO documents (path) VALUES (?) ON CONFLICT DO NOTHING"
   154→    );
   155→    const getDocId = db.prepare(
   156→      "SELECT id FROM documents WHERE path = ?"
   157→    );
   158→    const insertSym = db.prepare(
   159→      "INSERT INTO symbols (name, kind, definition, document_id) VALUES (?, ?, ?, ?)"
   160→    );
   161→
   162→    const tx = db.transaction(() => {
   163→      const docPaths = new Set<string>();
   164→      let symCount = 0;
   165→
   166→      for (const sym of symbols) {
   167→        if (sym.documentPath) docPaths.add(sym.documentPath);
   168→      }
   169→
   170→      for (const p of docPaths) {
   171→        insertDoc.run(p);
   172→      }
   173→
   174→      for (const sym of symbols) {
   175→        const docId = sym.documentPath
   176→          ? (getDocId.get(sym.documentPath) as { id: number } | undefined)
   177→              ?.id ?? null
   178→          : null;
   179→        insertSym.run(sym.name, sym.kind, sym.definition ?? null, docId);
   180→        symCount++;
   181→      }
   182→
   183→      return { documentCount: docPaths.size, symbolCount: symCount };
   184→    });
   185→
   186→    const counts = tx();
   187→    db.close();
   188→
   189→    return {
   190→      success: true,
   191→      dbPath,
   192→      documentCount: counts.documentCount,
   193→      symbolCount: counts.symbolCount,
   194→    };
   195→  } catch (err) {
   196→    db.close();
   197→    const msg = err instanceof Error ? err.message : String(err);
   198→    return { success: false, error: `sqlite write failed: ${msg}` };
   199→  }
   200→}
   201→

