{"role":"user","content":[{"tool_use_id":"call_b1e25bd2a1af4b7baaff88ff","type":"tool_result","content":"     1→#!/usr/bin/env node
     2→import {
     3→  findDefinition,
     4→  findReferences,
     5→  findCallers,
     6→  QueryResult,
     7→} from "../query/engine.js";
     8→
     9→type QueryCommand = "findDefinition" | "findReferences" | "findCallers";
    10→
    11→function usage(): void {
    12→  const lines = [
    13→    "Usage: fg-query <command> <symbol> [options]",
    14→    "",
    15→    "Commands:",
    16→    "  findDefinition <symbol>   Find where a symbol is defined",
    17→    "  findReferences <symbol>   Find all references to a symbol",
    18→    "  findCallers <symbol>      Find all callers of a symbol",
    19→    "",
    20→    "Options:",
    21→    "  --cwd <dir>               Working directory (default: git root or cwd)",
    22→    "  --json                    Output results as JSON",
    23→    "  -h, --help                Show this help",
    24→  ];
    25→  console.error(lines.join("\n"));
    26→}
    27→
    28→function formatResult(r: QueryResult): string {
    29→  const kindTag =
    30→    r.kind === "definition"
    31→      ? "[DEF]"
    32→      : r.kind === "call"
    33→        ? "[CALL]"
    34→        : "[REF]";
    35→  return `${kindTag} ${r.file}:${r.line}  ${r.text}`;
    36→}
    37→
    38→function main(): void {
    39→  const args = process.argv.slice(2);
    40→
    41→  if (args.length === 0 || args.includes("-h") || args.includes("--help")) {
    42→    usage();
    43→    process.exit(args.length === 0 ? 1 : 0);
    44→  }
    45→
    46→  const validCommands = new Set<string>([
    47→    "findDefinition",
    48→    "findReferences",
    49→    "findCallers",
    50→  ]);
    51→  const command = args[0] as QueryCommand;
    52→
    53→  if (!validCommands.has(command)) {
    54→    console.error(`Error: unknown command "${command}"\n`);
    55→    usage();
    56→    process.exit(2);
    57→  }
    58→
    59→  const symbol = args[1];
    60→  if (!symbol) {
    61→    console.error(`Error: <symbol> is required for "${command}"\n`);
    62→    usage();
    63→    process.exit(2);
    64→  }
    65→
    66→  let cwd: string | undefined;
    67→  let jsonOutput = false;
    68→  for (let i = 2; i < args.length; i++) {
    69→    if (args[i] === "--cwd" && args[i + 1]) {
    70→      cwd = args[i + 1];
    71→      i++;
    72→    } else if (args[i] === "--json") {
    73→      jsonOutput = true;
    74→    }
    75→  }
    76→
    77→  const options = cwd ? { cwd } : {};
    78→  let results: QueryResult[];
    79→
    80→  switch (command) {
    81→    case "findDefinition":
    82→      results = findDefinition(symbol, options);
    83→      break;
    84→    case "findReferences":
    85→      results = findReferences(symbol, options);
    86→      break;
    87→    case "findCallers":
    88→      results = findCallers(symbol, options);
    89→      break;
    90→  }
    91→
    92→  if (jsonOutput) {
    93→    console.log(JSON.stringify(results, null, 2));
    94→  } else {
    95→    if (results.length === 0) {
    96→      console.log(`No results found for "${symbol}".`);
    97→      return;
    98→    }
    99→    console.log(`Found ${results.length} result(s) for "${symbol}":\n`);
   100→    results.forEach((r) => console.log(formatResult(r)));
   101→  }
   102→}
   103→
   104→main();
   105→

