{"type":"tool_use","id":"call_6bb3616173f74ec7acc1c59b","name":"Write","input":{"file_path":"/Users/xin/auto-skills/.claude/worktrees/worker-task-d-mnpffkol/src/query/engine.ts","content":"import { execSync } from "child_process";
import Database from "better-sqlite3";
import { join } from "path";
import { existsSync } from "fs";

export interface QueryResult {
  file: string;
  line: number;
  column: number;
  text: string;
  kind: "definition" | "reference" | "call";
}

export interface QueryOptions {
  cwd?: string;
  dbPath?: string;
}

function findDbPath(cwd: string): string | null {
  const name = cwd.split("/").pop() || "project";
  const candidates = [
    join(cwd, `${name}.fg-index.db`),
    join(cwd, ".ai", "mindkeeper", "index.db"),
    join(cwd, ".ai", "mindkeeper", "graph.db"),
    join(cwd, "index.db"),
  ];
  for (const p of candidates) {
    if (existsSync(p)) return p;
  }
  return null;
}

function rgAvailable(): boolean {
  try {
    execSync("rg --version", { stdio: "pipe" });
    return true;
  } catch {
    return false;
  }
}

function escapeRegex(s: string): string {
  return s.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

function hasTable(db: Database.Database, tableName: string): boolean {
  const row = db
    .prepare(
      "SELECT name FROM sqlite_master WHERE type='table' AND name=?"
    )
    .get(tableName) as { name: string } | undefined;
  return row !== undefined;
}

export function findDefinition(symbol: string, options: QueryOptions = {}): QueryResult[] {
  const cwd = options.cwd || process.cwd();
  const dbPath = options.dbPath || findDbPath(cwd);
  const results: QueryResult[] = [];

  if (dbPath) {
    try {
      const db = new Database(dbPath, { readonly: true });

      if (hasTable(db, "symbols")) {
        const rows = db
          .prepare(
            `SELECT s.name, s.definition, s.kind
             FROM symbols s
             WHERE s.name LIKE ? AND s.definition IS NOT NULL`
          )
          .all(`%${symbol}%`) as Array<{
          name: string;
          definition: string;
          kind: string;
        }>;

        for (const r of rows) {
          const parsed = parseDefinitionLocation(r.definition);
          if (parsed) {
            results.push({
              ...parsed,
              text: `${r.kind}: ${r.name}`,
              kind: "definition",
            });
          }
        }
      }

      if (hasTable(db, "nodes")) {
        const rows = db
          .prepare(
            `SELECT n.name, n.file_path, n.line, n.column, n.detail
             FROM nodes n
             WHERE n.type = 'symbol' AND n.name LIKE ?
               AND n.line IS NOT NULL`
          )
          .all(`%${symbol}%`) as Array<{
          name: string;
          file_path: string;
          line: number;
          column: number | null;
          detail: string | null;
        }>;

        for (const r of rows) {
          const isDuplicate = results.some(
            (existing) =>
              existing.file === r.file_path && existing.line === r.line
          );
          if (!isDuplicate) {
            results.push({
              file: r.file_path,
              line: r.line,
              column: r.column ?? 0,
              text: r.detail ?? r.name,
              kind: "definition",
            });
          }
        }

        if (results.length === 0) {
          const edgeRows = db
            .prepare(
              `SELECT n.name, n.file_path, n.line, n.column, n.detail
               FROM edges e
               JOIN nodes n ON e.target_id = n.id
               WHERE e.kind = 'defines'
                 AND EXISTS (
                   SELECT 1 FROM nodes src
                   WHERE src.id = e.source_id AND src.name LIKE ?
                 )`
            )
            .all(`%${symbol}%`) as Array<{
            name: string;
            file_path: string;
            line: number | null;
            column: number | null;
            detail: string | null;
          }>;

          for (const r of edgeRows) {
            if (r.line != null) {
              results.push({
                file: r.file_path,
                line: r.line,
                column: r.column ?? 0,
                text: r.detail ?? r.name,
                kind: "definition",
              });
            }
          }
        }
      }

      db.close();
    } catch {
      // Fall through to grep
    }
  }

  if (results.length > 0) return results;

  return grepDefinitions(symbol, cwd);
}

function grepDefinitions(symbol: string, cwd: string): QueryResult[] {
  const escaped = escapeRegex(symbol);
  const cmd = rgAvailable()
    ? `rg -n --type ts "^(export\\s+)?(async\\s+)?(function|const|let|class|interface|type|enum)\\s+${escaped}\\b"`
    : `grep -rn -E "^(export\\s+)?(async\\s+)?(function|const|let|class|interface|type|enum)\\s+${escaped}\\b" --include="*.ts"`;

  try {
    const output = execSync(cmd, {
      cwd,
      encoding: "utf-8",
      maxBuffer: 10 * 1024 * 1024,
    });
    return parseGrepOutput(output).map((r) => ({
      ...r,
      kind: "definition" as const,
    }));
  } catch {
    return [];
  }
}

function parseDefinitionLocation(
  definition: string | null | undefined
): { file: string; line: number; column: number } | null {
  if (!definition) return null;
  const parts = definition.split(":");
  if (parts.length < 2) return null;
  const line = parseInt(parts[1], 10);
  if (isNaN(line)) return null;
  return {
    file: parts[0],
    line,
    column: parts.length >= 3 ? parseInt(parts[2], 10) || 0 : 0,
  };
}

export function findReferences(symbol: string, options: QueryOptions = {}): QueryResult[] {
  const cwd = options.cwd || process.cwd();
  const dbPath = options.dbPath || findDbPath(cwd);
  const results: QueryResult[] = [];

  if (dbPath) {
    try {
      const db = new Database(dbPath, { readonly: true });

      if (hasTable(db, "nodes")) {
        const symbolNode = db
          .prepare(
            `SELECT id, file_path, line FROM nodes
             WHERE type = 'symbol' AND name LIKE ?
             LIMIT 1`
          )
          .get(`%${symbol}%`) as { id: number; file_path: string; line: number } | undefined;

        if (symbolNode) {
          const refEdges = db
            .prepare(
              `SELECT n.name, n.file_path, n.line, n.column, n.detail
               FROM edges e
               JOIN nodes n ON e.source_id = n.id
               WHERE e.target_id = ? AND e.kind = 'references'`
            )
            .all(symbolNode.id) as Array<{
            name: string;
            file_path: string;
            line: number | null;
            column: number | null;
            detail: string | null;
          }>;

          for (const r of refEdges) {
            results.push({
              file: r.file_path,
              line: r.line ?? 0,
              column: r.column ?? 0,
              text: r.detail ?? r.name,
              kind: "reference",
            });
          }
        }
      }

      if (hasTable(db, "symbols") && results.length === 0) {
        const symRows = db
          .prepare(
            `SELECT s.name, s.kind, s.definition
             FROM symbols s
             WHERE s.name LIKE ?`
          )
          .all(`%${symbol}%`) as Array<{
          name: string;
          kind: string;
          definition: string | null;
        }>;

        for (const r of symRows) {
          const loc = parseDefinitionLocation(r.definition);
          if (loc) {
            results.push({
              ...loc,
              text: `${r.kind}: ${r.name}`,
              kind: "reference",
            });
          }
        }
      }

      db.close();
    } catch {
      // Fall through to grep
    }
  }

  if (results.length > 0) return results;

  const pattern = `\\b${escapeRegex(symbol)}\\b`;
  const cmd = rgAvailable()
    ? `rg -n --type ts ${JSON.stringify(pattern)}`
    : `grep -rn ${JSON.stringify(pattern)} --include="*.ts"`;

  try {
    const output = execSync(cmd, {
      cwd,
      encoding: "utf-8",
      maxBuffer: 10 * 1024 * 1024,
    });
    return parseGrepOutput(output).map((r) => ({
      ...r,
      kind: "reference" as const,
    }));
  } catch {
    return [];
  }
}

export function findCallers(symbol: string, options: QueryOptions = {}): QueryResult[] {
  const cwd = options.cwd || process.cwd();
  const dbPath = options.dbPath || findDbPath(cwd);
  const results: QueryResult[] = [];

  if (dbPath) {
    try {
      const db = new Database(dbPath, { readonly: true });

      if (hasTable(db, "nodes")) {
        const funcNode = db
          .prepare(
            `SELECT id, name FROM nodes
             WHERE type = 'symbol' AND name LIKE ?
             LIMIT 1`
          )
          .get(`%${symbol}%`) as { id: number; name: string } | undefined;

        if (funcNode) {
          const callerEdges = db
            .prepare(
              `SELECT n.name, n.file_path, n.line, n.column, n.detail
               FROM edges e
               JOIN nodes n ON e.source_id = n.id
               WHERE e.target_id = ? AND e.kind = 'calls'`
            )
            .all(funcNode.id) as Array<{
            name: string;
            file_path: string;
            line: number | null;
            column: number | null;
            detail: string | null;
          }>;

          for (const r of callerEdges) {
            results.push({
              file: r.file_path,
              line: r.line ?? 0,
              column: r.column ?? 0,
              text: r.detail ?? r.name,
              kind: "call",
            });
          }
        }
      }

      if (hasTable(db, "symbols") && results.length === 0) {
        const symRows = db
          .prepare(
            `SELECT s.name, s.kind
             FROM symbols s
             WHERE s.name LIKE ?`
          )
          .all(`%${symbol}%`) as Array<{ name: string; kind: string }>;

        if (symRows.length > 0) {
          return grepCallers(symbol, cwd);
        }
      }

      db.close();
    } catch {
      // Fall through to grep
    }
  }

  if (results.length > 0) return results;

  return grepCallers(symbol, cwd);
}

function grepCallers(symbol: string, cwd: string): QueryResult[] {
  const pattern = `${escapeRegex(symbol)}\\s*\\(`;
  const cmd = rgAvailable()
    ? `rg -n --type ts ${JSON.stringify(pattern)}`
    : `grep -rn ${JSON.stringify(pattern)} --include="*.ts"`;

  try {
    const output = execSync(cmd, {
      cwd,
      encoding: "utf-8",
      maxBuffer: 10 * 1024 * 1024,
    });
    return parseGrepOutput(output).map((r) => ({
      ...r,
      kind: "call" as const,
    }));
  } catch {
    return [];
  }
}

function parseGrepOutput(output: string): Omit<QueryResult, "kind">[] {
  if (!output.trim()) return [];
  return output
    .trim()
    .split("\n")
    .map((line) => {
      const match = line.match(/^([^:]+):(\d+):(\d+)?:?(.*)$/);
      if (!match) return null;
      return {
        file: match[1],
        line: parseInt(match[2], 10),
        column: match[3] ? parseInt(match[3], 10) : 0,
        text: (match[4] ?? "").trim(),
      };
    })
    .filter((r): r is Omit<QueryResult, "kind"> => r !== null);
}
