   169→    ? `rg -n --type ts "^(export\\s+)?(async\\s+)?(function|const|let|class|interface|type|enum)\\s+${escaped}\\b"`
   170→    : `grep -rn -E "^(export\\s+)?(async\\s+)?(function|const|let|class|interface|type|enum)\\s+${escaped}\\b" --include="*.ts"`;
   171→
   172→  try {
