   201→
   202→export function findReferences(symbol: string, options: QueryOptions = {}): QueryResult[] {
   203→  const cwd = options.cwd || process.cwd();
   204→  const dbPath = options.dbPath || findDbPath(cwd);
   205→  const results: QueryResult[] = [];
   206→
   207→  if (dbPath) {
   208→    try {
   209→      const db = new Database(dbPath, { readonly: true });
   210→
   211→      if (hasTable(db, "nodes")) {
   212→        const symbolNode = db
   213→          .prepare(
   214→            `SELECT id, file_path, line FROM nodes
   215→             WHERE type = 'symbol' AND name LIKE ?
   216→             LIMIT 1`
   217→          )
   218→          .get(`%${symbol}%`) as { id: number; file_path: string; line: number } | undefined;
   219→
   220→        if (symbolNode) {
   221→          const refEdges = db
   222→            .prepare(
   223→              `SELECT n.name, n.file_path, n.line, n.column, n.detail
   224→               FROM edges e
   225→               JOIN nodes n ON e.source_id = n.id
   226→               WHERE e.target_id = ? AND e.kind = 'references'`
   227→            )
   228→            .all(symbolNode.id) as Array<{
   229→            name: string;
   230→            file_path: string;
   231→            line: number | null;
   232→            column: number | null;
   233→            detail: string | null;
   234→          }>;
   235→
   236→          for (const r of refEdges) {
   237→            results.push({
   238→              file: r.file_path,
   239→              line: r.line ?? 0,
   240→              column: r.column ?? 0,
   241→              text: r.detail ?? r.name,
   242→              kind: "reference",
   243→            });
   244→          }
   245→        }
   246→      }
   247→
   248→      if (hasTable(db, "symbols") && results.length === 0) {
   249→        const symRows = db
   250→          .prepare(
   251→            `SELECT s.name, s.kind, s.definition
   252→             FROM symbols s
   253→             WHERE s.name LIKE ?`
   254→          )
   255→          .all(`%${symbol}%`) as Array<{
   256→          name: string;
   257→          kind: string;
   258→          definition: string | null;
   259→        }>;
   260→
   261→        for (const r of symRows) {
   262→          const loc = parseDefinitionLocation(r.definition);
   263→          if (loc) {
   264→            results.push({
   265→              ...loc,
   266→              text: `${r.kind}: ${r.name}`,
   267→              kind: "reference",
   268→            });
   269→          }
