   286→  try {
   287→    const output = execSync(cmd, {
   288→      cwd,
   289→      encoding: "utf-8",
   290→      maxBuffer: 10 * 1024 * 1024,
   291→    });
   292→    return parseGrepOutput(output).map((r) => ({
   293→      ...r,
