   301→export function findCallers(symbol: string, options: QueryOptions = {}): QueryResult[] {
   302→  const cwd = options.cwd || process.cwd();
   303→  const dbPath = options.dbPath || findDbPath(cwd);
   304→  const results: QueryResult[] = [];
   305→
   306→  if (dbPath) {
   307→    try {
   308→      const db = new Database(dbPath, { readonly: true });
   309→
   310→      if (hasTable(db, "nodes")) {
   311→        const funcNode = db
   312→          .prepare(
   313→            `SELECT id, name FROM nodes
   314→             WHERE type = 'symbol' AND name LIKE ?
   315→             LIMIT 1`
   316→          )
   317→          .get(`%${symbol}%`) as { id: number; name: string } | undefined;
   318→
   319→        if (funcNode) {
   320→          const callerEdges = db
   321→            .prepare(
   322→              `SELECT n.name, n.file_path, n.line, n.column, n.detail
   323→               FROM edges e
   324→               JOIN nodes n ON e.source_id = n.id
   325→               WHERE e.target_id = ? AND e.kind = 'calls'`
   326→            )
   327→            .all(funcNode.id) as Array<{
   328→            name: string;
   329→            file_path: string;
   330→            line: number | null;
   331→            column: number | null;
   332→            detail: string | null;
   333→          }>;
   334→
   335→          for (const r of callerEdges) {
   336→            results.push({
   337→              file: r.file_path,
   338→              line: r.line ?? 0,
   339→              column: r.column ?? 0,
   340→              text: r.detail ?? r.name,
   341→              kind: "call",
   342→            });
   343→          }
   344→        }
   345→      }
   346→
   347→      if (hasTable(db, "symbols") && results.length === 0) {
   348→        const symRows = db
   349→          .prepare(
   350→            `SELECT s.name, s.kind
   351→             FROM symbols s
   352→             WHERE s.name LIKE ?`
   353→          )
   354→          .all(`%${symbol}%`) as Array<{ name: string; kind: string }>;
   355→
   356→        if (symRows.length > 0) {
   357→          return grepCallers(symbol, cwd);
   358→        }
   359→      }
   360→
   361→      db.close();
   362→    } catch {
   363→      // Fall through to grep
   364→    }
