   371→
   372→function grepCallers(symbol: string, cwd: string): QueryResult[] {
   373→  const pattern = `${escapeRegex(symbol)}\\s*\\(`;
   374→  const cmd = rgAvailable()
   375→    ? `rg -n --type ts ${JSON.stringify(pattern)}`
   376→    : `grep -rn ${JSON.stringify(pattern)} --include="*.ts"`;
   377→
   378→  try {
   379→    const output = execSync(cmd, {
   380→      cwd,
   381→      encoding: "utf-8",
   382→      maxBuffer: 10 * 1024 * 1024,
   383→    });
   384→    return parseGrepOutput(output).map((r) => ({
   385→      ...r,
   386→      kind: "call" as const,
   387→    }));
   388→  } catch {
