   390→  }
   391→}
   392→
   393→function parseGrepOutput(output: string): Omit<QueryResult, "kind">[] {
   394→  if (!output.trim()) return [];
   395→  return output
   396→    .trim()
   397→    .split("\n")
   398→    .map((line) => {
   399→      const match = line.match(/^([^:]+):(\d+):(\d+)?:?(.*)$/);
   400→      if (!match) return null;
   401→      return {
   402→        file: match[1],
   403→        line: parseInt(match[2], 10),
   404→        column: match[3] ? parseInt(match[3], 10) : 0,
   405→        text: (match[4] ?? "").trim(),
   406→      };
   407→    })
   408→    .filter((r): r is Omit<QueryResult, "kind"> => r !== null);
   409→}
