    22→
    23→function isGitRepo(cwd: string): boolean {
    24→  const gitDir = resolve(cwd, '.git');
    25→  if (existsSync(gitDir)) return true;
    26→
    27→  try {
    28→    execSync('git rev-parse --git-dir', { cwd, stdio: 'pipe' });
