    38→      'git rev-parse --verify refs/notes/folder-graphy-index 2>/dev/null || echo ""',
    39→      { cwd, stdio: 'pipe', encoding: 'utf-8' }
    40→    );
    41→    const ref = result.trim();
    42→    return ref || null;
    43→  } catch {
    44→    return null;
    45→  }
    46→}
    47→
    48→function getDefaultBranchRef(cwd: string): string {
    49→  try {
    50→    const result = execSync(
    51→      'git rev-parse --verify HEAD',
    52→      { cwd, stdio: 'pipe', encoding: 'utf-8' }
