    58→}
    59→
    60→function parseDiffNameStatus(output: string): FileChange[] {
    61→  const files: FileChange[] = [];
    62→  const lines = output.trim().split('\n').filter(Boolean);
    63→
    64→  for (const line of lines) {
    65→    const parts = line.split('\t');
    66→    if (parts.length < 2) continue;
    67→
    68→    const status = parts[0][0];
    69→    const path = parts[parts.length - 1];
    70→
    71→    switch (status) {
    72→      case 'A':
    73→        files.push({ path, status: 'added' });
    74→        break;
    75→      case 'M':
    76→        files.push({ path, status: 'modified' });
    77→        break;
    78→      case 'D':
    79→        files.push({ path, status: 'deleted' });
    80→        break;
    81→      case 'R':
    82→        files.push({
    83→          path,
    84→          status: 'renamed',
    85→          oldPath: parts[1]
    86→        });
    87→        break;
    88→    }
    89→  }
    90→
    91→  return files;
    92→}
    93→
    94→export function getChangedFiles(options: GitDiffOptions = {}): DiffResult {
    95→  const cwd = options.cwd || process.cwd();
    96→
    97→  if (!isGitRepo(cwd)) {
    98→    throw new Error(`Not a git repository: ${cwd}`);
