{"role":"user","content":[{"tool_use_id":"tool_SWCrtLfZf5bHlZBtFnLjpKN4","type":"tool_result","content":"     1→import { execSync } from "child_process";
     2→import Database from "better-sqlite3";
     3→import { join } from "path";
     4→import { existsSync } from "fs";
     5→
     6→export interface QueryResult {
     7→  file: string;
     8→  line: number;
     9→  column: number;
    10→  text: string;
    11→  kind: "definition" | "reference" | "call";
    12→}
    13→
    14→export interface QueryOptions {
    15→  cwd?: string;
    16→  dbPath?: string;
    17→}
    18→
    19→function findDbPath(cwd: string): string | null {
    20→  const name = cwd.split("/").pop() || "project";
    21→  const candidates = [
    22→    join(cwd, `${name}.fg-index.db`),
    23→    join(cwd, ".ai", "mindkeeper", "index.db"),
    24→    join(cwd, "index.db"),
    25→  ];
    26→  for (const p of candidates) {
    27→    if (existsSync(p)) return p;
    28→  }
    29→  return null;
    30→}
    31→
    32→function rgAvailable(): boolean {
    33→  try {
    34→    execSync("rg --version", { stdio: "pipe" });
    35→    return true;
    36→  } catch {
    37→    return false;
    38→  }
    39→}
    40→
    41→function escapeRegex(s: string): string {
    42→  return s.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
    43→}
    44→
    45→export function findDefinition(symbol: string, options: QueryOptions = {}): QueryResult[] {
    46→  const cwd = options.cwd || process.cwd();
    47→  const dbPath = options.dbPath || findDbPath(cwd);
    48→
    49→  if (dbPath) {
    50→    try {
    51→      const db = new Database(dbPath);
    52→      const stmt = db.prepare(
    53→        `SELECT s.name, s.definition, s.kind
    54→         FROM symbols s
    55→         WHERE s.name LIKE ? AND s.definition IS NOT NULL`
    56→      );
    57→      const rows = stmt.all(`%${symbol}%`) as Array<{ name: string; definition: string; kind: string }>;
    58→      db.close();
    59→
    60→      const results: QueryResult[] = [];
    61→      for (const r of rows) {
    62→        const parts = r.definition?.split(":");
    63→        if (!parts || parts.length < 2) continue;
    64→        results.push({
    65→          file: parts[0],
    66→          line: parseInt(parts[1], 10) || 0,
    67→          column: 0,
    68→          text: `${r.kind}: ${r.name}`,
    69→          kind: "definition",
    70→        });
    71→      }
    72→      return results;
    73→    } catch {
    74→      // Fall through to grep
    75→    }
    76→  }
    77→
    78→  // Fallback: grep-based search
    79→  const pattern = `\\b${escapeRegex(symbol)}\\b`;
    80→  const cmd = rgAvailable()
    81→    ? `rg -n --type ts "^(export\\s+)?(async\\s+)?(function|const|let|class|interface)\\s+${escapeRegex(symbol)}"`
    82→    : `grep -rn "^(export\\s\+\)\?\(async\\s\+\)\?\(function\\|const\\|let\\|class\\|interface\)\\s\+${escapeRegex(symbol)}" --include="*.ts"`;
    83→
    84→  try {
    85→    const output = execSync(cmd, { cwd, encoding: "utf-8", maxBuffer: 10 * 1024 * 1024 });
    86→    return parseGrepOutput(output).map((r) => ({ ...r, kind: "definition" as const }));
    87→  } catch {
    88→    return [];
    89→  }
    90→}
    91→
    92→export function findReferences(symbol: string, options: QueryOptions = {}): QueryResult[] {
    93→  const cwd = options.cwd || process.cwd();
    94→  const pattern = `\\b${escapeRegex(symbol)}\\b`;
    95→
    96→  const cmd = rgAvailable()
    97→    ? `rg -n --type ts ${JSON.stringify(pattern)}`
    98→    : `grep -rn ${JSON.stringify(pattern)} --include="*.ts"`;
    99→
   100→  try {
   101→    const output = execSync(cmd, { cwd, encoding: "utf-8", maxBuffer: 10 * 1024 * 1024 });
   102→    return parseGrepOutput(output).map((r) => ({ ...r, kind: "reference" as const }));
   103→  } catch {
   104→    return [];
   105→  }
   106→}
   107→
   108→export function findCallers(symbol: string, options: QueryOptions = {}): QueryResult[] {
   109→  const cwd = options.cwd || process.cwd();
   110→  const pattern = `${escapeRegex(symbol)}\\s*\\(`;
   111→
   112→  const cmd = rgAvailable()
   113→    ? `rg -n --type ts ${JSON.stringify(pattern)}`
   114→    : `grep -rn ${JSON.stringify(pattern)} --include="*.ts"`;
   115→
   116→  try {
   117→    const output = execSync(cmd, { cwd, encoding: "utf-8", maxBuffer: 10 * 1024 * 1024 });
   118→    return parseGrepOutput(output).map((r) => ({ ...r, kind: "call" as const }));
   119→  } catch {
   120→    return [];
   121→  }
   122→}
   123→
   124→function parseGrepOutput(output: string): Array<{ file: string; line: number; column: number; text: string }> {
   125→  if (!output.trim()) return [];
   126→  const results: Array<{ file: string; line: number; column: number; text: string }> = [];
   127→  for (const line of output.trim().split("\n")) {
   128→    const match = line.match(/^([^:]+):(\d+):(.*)$/);
   129→    if (!match) continue;
   130→    results.push({
   131→      file: match[1],
   132→      line: parseInt(match[2], 10),
   133→      column: 0,
   134→      text: match[3].trim(),
   135→    });
   136→  }
   137→  return results;
   138→}
