{"role":"user","content":[{"tool_use_id":"tool_THEV9Z2YHcJavFGSrvgSh3qv","type":"tool_result","content":"     1→import { existsSync, statSync, readdirSync } from 'fs';
     2→import { join, resolve } from 'path';
     3→
     4→export interface IndexState {
     5→  exists: boolean;
     6→  expired: boolean;
     7→  path: string | null;
     8→  ageMs: number | null;
     9→}
    10→
    11→export interface MindKeeperConfig {
    12→  enabled: boolean;
    13→  indexDir: string;
    14→  maxAgeMs: number;
    15→  triggerOnEntry: boolean;
    16→  silent: boolean;
    17→}
    18→
    19→const DEFAULT_CONFIG: MindKeeperConfig = {
    20→  enabled: true,
    21→  indexDir: '.ai/mindkeeper',
    22→  maxAgeMs: 4 * 60 * 60 * 1000,
    23→  triggerOnEntry: true,
    24→  silent: false,
    25→};
    26→
    27→const INDEX_FILES = ['index.json', 'index.db', 'graph.json'];
    28→
    29→function findProjectRoot(startPath: string): string | null {
    30→  let dir = resolve(startPath);
    31→  const visited = new Set<string>();
    32→  while (!visited.has(dir)) {
    33→    visited.add(dir);
    34→    if (existsSync(join(dir, '.git'))) return dir;
    35→    if (existsSync(join(dir, '.ai'))) return dir;
    36→    const parent = join(dir, '..');
    37→    if (parent === dir) break;
    38→    dir = parent;
    39→  }
    40→  return null;
    41→}
    42→
    43→function probeIndexPath(root: string, config: MindKeeperConfig): string | null {
    44→  const base = join(root, config.indexDir);
    45→  if (!existsSync(base)) return null;
    46→  for (const name of INDEX_FILES) {
    47→    const candidate = join(base, name);
    48→    if (existsSync(candidate)) return candidate;
    49→  }
    50→  const entries = readdirSync(base).filter(f => !f.startsWith('.'));
    51→  if (entries.length > 0) return join(base, entries[0]);
    52→  return null;
    53→}
    54→
    55→export function checkIndexStatus(projectRoot: string, config?: Partial<MindKeeperConfig>): IndexState {
    56→  const cfg = { ...DEFAULT_CONFIG, ...config };
    57→  const root = projectRoot || findProjectRoot(process.cwd());
    58→  if (!root) return { exists: false, expired: false, path: null, ageMs: null };
    59→
    60→  const indexPath = probeIndexPath(root, cfg);
    61→  if (!indexPath) return { exists: false, expired: true, path: null, ageMs: null };
    62→
    63→  try {
    64→    const stat = statSync(indexPath);
    65→    const ageMs = Date.now() - stat.mtimeMs;
    66→    return {
