{"role":"user","content":[{"tool_use_id":"tool_1XcrcKlXUwwTNLyASCwhUvAf","type":"tool_result","content":"     1→import { execSync } from 'child_process';
     2→import { existsSync } from 'fs';
     3→import { resolve } from 'path';
     4→
     5→export interface GitDiffOptions {
     6→  cwd?: string;
     7→  fromRef?: string;
     8→  toRef?: string;
     9→}
    10→
    11→export interface FileChange {
    12→  path: string;
    13→  status: 'added' | 'modified' | 'deleted' | 'renamed';
    14→  oldPath?: string;
    15→}
    16→
    17→export interface DiffResult {
    18→  files: FileChange[];
    19→  fromRef: string;
    20→  toRef: string;
    21→}
    22→
    23→function isGitRepo(cwd: string): boolean {
    24→  const gitDir = resolve(cwd, '.git');
    25→  if (existsSync(gitDir)) return true;
    26→
    27→  try {
    28→    execSync('git rev-parse --git-dir', { cwd, stdio: 'pipe' });
    29→    return true;
    30→  } catch {
    31→    return false;
    32→  }
    33→}
    34→
    35→function getLastIndexedRef(cwd: string): string | null {
    36→  try {
    37→    const result = execSync(
    38→      'git rev-parse --verify refs/notes/folder-graphy-index 2>/dev/null || echo ""',
    39→      { cwd, stdio: 'pipe', encoding: 'utf-8' }
    40→    );
    41→    const ref = result.trim();
    42→    return ref || null;
    43→  } catch {
    44→    return null;
    45→  }
    46→}
    47→
    48→function getDefaultBranchRef(cwd: string): string {
    49→  try {
    50→    const result = execSync(
    51→      'git rev-parse --verify HEAD',
    52→      { cwd, stdio: 'pipe', encoding: 'utf-8' }
    53→    );
    54→    return result.trim();
    55→  } catch {
    56→    throw new Error('Failed to get HEAD ref');
    57→  }
    58→}
    59→
    60→function parseDiffNameStatus(output: string): FileChange[] {
    61→  const files: FileChange[] = [];
    62→  const lines = output.trim().split('\n').filter(Boolean);
    63→
    64→  for (const line of lines) {
    65→    const parts = line.split('\t');
    66→    if (parts.length < 2) continue;
    67→
    68→    const status = parts[0][0];
    69→    const path = parts[parts.length - 1];
    70→
    71→    switch (status) {
    72→      case 'A':
    73→        files.push({ path, status: 'added' });
    74→        break;
    75→      case 'M':
    76→        files.push({ path, status: 'modified' });
    77→        break;
    78→      case 'D':
    79→        files.push({ path, status: 'deleted' });
    80→        break;
    81→      case 'R':
    82→        files.push({
    83→          path,
    84→          status: 'renamed',
    85→          oldPath: parts[1]
    86→        });
    87→        break;
    88→    }
    89→  }
    90→
    91→  return files;
    92→}
    93→
    94→export function getChangedFiles(options: GitDiffOptions = {}): DiffResult {
    95→  const cwd = options.cwd || process.cwd();
    96→
    97→  if (!isGitRepo(cwd)) {
    98→    throw new Error(`Not a git repository: ${cwd}`);
    99→  }
   100→
   101→  const fromRef = options.fromRef || getLastIndexedRef(cwd) || 'HEAD~1';
   102→  const toRef = options.toRef || getDefaultBranchRef(cwd);
   103→
   104→  try {
   105→    const output = execSync(
   106→      `git diff --name-status ${fromRef}..${toRef}`,
   107→      { cwd, stdio: 'pipe', encoding: 'utf-8' }
   108→    );
   109→
   110→    const files = parseDiffNameStatus(output);
   111→
   112→    return {
   113→      files,
   114→      fromRef,
   115→      toRef
   116→    };
   117→  } catch (error) {
   118→    throw new Error(`Failed to get git diff: ${error}`);
   119→  }
   120→}
   121→
   122→export function getUntrackedFiles(cwd: string = process.cwd()): string[] {
   123→  if (!isGitRepo(cwd)) {
   124→    return [];
   125→  }
   126→
   127→  try {
   128→    const output = execSync(
   129→      'git ls-files --others --exclude-standard',
   130→      { cwd, stdio: 'pipe', encoding: 'utf-8' }
   131→    );
   132→
   133→    return output.trim().split('\n').filter(Boolean);
   134→  } catch {
   135→    return [];
   136→  }
   137→}
   138→
   139→export function saveIndexRef(ref: string, cwd: string = process.cwd()): void {
   140→  if (!isGitRepo(cwd)) {
   141→    throw new Error(`Not a git repository: ${cwd}`);
   142→  }
   143→
   144→  try {
   145→    execSync(
   146→      `git notes --ref folder-graphy-index add -m "${ref}" HEAD`,
   147→      { cwd, stdio: 'pipe' }
   148→    );
   149→  } catch (error) {
   150→    throw new Error(`Failed to save index ref: ${error}`);
   151→  }
   152→}
   153→

