{"type":"tool_use","id":"tool_s8brzer9qKKa9nYFjN968ane","name":"Write","input":{"file_path":"/Users/xin/auto-skills/.claude/worktrees/worker-task-g-mnpfrbx2/src/indexer/incremental.ts","content":"import { existsSync, readFileSync } from "fs";
import { join, basename, resolve } from "path";
import { execFile, execSync } from "child_process";
import { promisify } from "util";
import Database from "better-sqlite3";
import { getChangedFiles, getUntrackedFiles, saveIndexRef, FileChange } from "../git/diff.js";
import { ProjectType, indexerCommand } from "./builder.js";

const execFileAsync = promisify(execFile);

export interface IncrementalIndexResult {
  success: boolean;
  dbPath?: string;
  filesChanged?: number;
  filesDeleted?: number;
  filesAdded?: number;
  symbolCount?: number;
  error?: string;
  fromRef?: string;
  toRef?: string;
}

interface ScipSymbol {
  name: string;
  kind: string;
  definition?: string;
  documentPath?: string;
}

function parseScipForFiles(scipPath: string, targetFiles: Set<string>): ScipSymbol[] {
  if (!existsSync(scipPath)) return [];

  const raw = readFileSync(scipPath, "utf-8");
  try {
    const doc = JSON.parse(raw);
    return extractSymbolsForFiles(doc, targetFiles);
  } catch {
    console.error("Warning: could not parse SCIP output");
    return [];
  }
}

function extractSymbolsForFiles(
  doc: Record<string, unknown>,
  targetFiles: Set<string>
): ScipSymbol[] {
  const symbols: ScipSymbol[] = [];
  const externalSymbols: Record<string, unknown> =
    (doc.external_symbols as Record<string, unknown>) ?? {};
  const internalSymbols: Record<string, unknown> =
    (doc.internal_symbols as Record<string, unknown>) ?? {};
  const documents: Record<string, unknown> =
    (doc.documents as Record<string, unknown>) ?? {};

  const allSymbols = { ...externalSymbols, ...internalSymbols };
  const pathByDocId: Record<string, string> = {};

  for (const [docId, docData] of Object.entries(documents)) {
    const relativePath = (docData as Record<string, unknown>).relative_path as
      | string
      | undefined;
    if (relativePath) pathByDocId[docId] = relativePath;
  }

  for (const [symbolKey, symData] of Object.entries(allSymbols)) {
    const sym = symData as Record<string, unknown>;
    const relationships = sym.relationships as Record<string, unknown> | undefined;
    const defRef = relationships?.definition_reference as
      | Record<string, unknown>
      | undefined;
    const docRef = defRef?.document as string | undefined;
    const documentPath = docRef ? pathByDocId[docRef] : undefined;

    if (documentPath && targetFiles.has(documentPath)) {
      symbols.push({
        name: symbolKey,
        kind: (sym.kind as string) ?? "unknown",
        definition: defRef
          ? `${pathByDocId[docRef ?? ""] ?? docRef}:${defRef.start_line ?? 0}`
          : undefined,
        documentPath,
      });
    }
  }

  return symbols;
}

function deleteSymbolsForFile(db: Database.Database, filePath: string): number {
  const deleteSym = db.prepare("DELETE FROM symbols WHERE document_id = (SELECT id FROM documents WHERE path = ?)");
  const deleteDoc = db.prepare("DELETE FROM documents WHERE path = ?");

  const result = deleteSym.run(filePath);
  deleteDoc.run(filePath);

  return result.changes;
}

function upsertSymbolsForFile(
  db: Database.Database,
  filePath: string,
  symbols: ScipSymbol[]
): number {
  const insertDoc = db.prepare(
    "INSERT INTO documents (path) VALUES (?) ON CONFLICT(path) DO UPDATE SET path=excluded.path"
  );
  const getDocId = db.prepare("SELECT id FROM documents WHERE path = ?");
  const deleteOldSymbols = db.prepare(
    "DELETE FROM symbols WHERE document_id = (SELECT id FROM documents WHERE path = ?)"
  );
  const insertSym = db.prepare(
    "INSERT INTO symbols (name, kind, definition, document_id) VALUES (?, ?, ?, ?)"
  );

  insertDoc.run(filePath);
  deleteOldSymbols.run(filePath);

  const docId = (getDocId.get(filePath) as { id: number } | undefined)?.id;
  if (!docId) return 0;

  let count = 0;
  for (const sym of symbols) {
    insertSym.run(sym.name, sym.kind, sym.definition ?? null, docId);
    count++;
  }

  return count;
}

function renameFileInIndex(db: Database.Database, oldPath: string, newPath: string): void {
  const updateDoc = db.prepare("UPDATE documents SET path = ? WHERE path = ?");
  updateDoc.run(newPath, oldPath);
}

export async function buildIndexIncremental(
  projectPath: string,
  projectType: ProjectType,
  options: { fromRef?: string; toRef?: string } = {}
): Promise<IncrementalIndexResult> {
  const spec = indexerCommand(projectType);
  if (!spec) {
    return { success: false, error: `unsupported project type: ${projectType}` };
  }

  const dbPath = join(projectPath, `${basename(projectPath)}.fg-index.db`);
  const dbExists = existsSync(dbPath);

  if (!dbExists) {
    return { success: false, error: "No existing index found. Run full index first." };
  }

  let diffResult;
  try {
    diffResult = getChangedFiles({
      cwd: projectPath,
      fromRef: options.fromRef,
      toRef: options.toRef,
    });
  } catch (error) {
    const msg = error instanceof Error ? error.message : String(error);
    return { success: false, error: `git diff failed: ${msg}` };
  }

  const changedFiles = diffResult.files.filter((f) =>
    projectType === "typescript" ? f.path.match(/\.(ts|tsx|js|jsx)$/) : f.path.match(/\.go$/)
  );

  if (changedFiles.length === 0) {
    saveIndexRef(diffResult.toRef, projectPath);
    return {
      success: true,
      dbPath,
      filesChanged: 0,
      filesDeleted: 0,
      filesAdded: 0,
      symbolCount: 0,
      fromRef: diffResult.fromRef,
      toRef: diffResult.toRef,
    };
  }

  try {
    await execFileAsync(spec.cmd, spec.args, { cwd: projectPath });
  } catch (err) {
    const msg = err instanceof Error ? err.message : String(err);
    return { success: false, error: `indexer failed: ${msg}` };
  }

  const scipPath = join(projectPath, "index.json");
  if (!existsSync(scipPath)) {
    return {
      success: false,
      error: `indexer produced no output at ${scipPath}`,
    };
  }

  const modifiedFiles = new Set(
    changedFiles.filter((f) => f.status === "added" || f.status === "modified" || f.status === "renamed").map((f) => f.path)
  );

  const db = new Database(dbPath);
  let filesDeleted = 0;
  let filesAdded = 0;
  let totalSymbols = 0;

  try {
    db.exec(`
      CREATE TABLE IF NOT EXISTS documents (
        id    INTEGER PRIMARY KEY AUTOINCREMENT,
        path  TEXT    NOT NULL UNIQUE,
        hash  TEXT
      );
      CREATE TABLE IF NOT EXISTS symbols (
        id            INTEGER PRIMARY KEY AUTOINCREMENT,
        name          TEXT    NOT NULL,
        kind          TEXT    NOT NULL,
        definition    TEXT,
        document_id   INTEGER REFERENCES documents(id) ON DELETE CASCADE
      );
      CREATE INDEX IF NOT EXISTS idx_symbols_name ON symbols(name);
      CREATE INDEX IF NOT EXISTS idx_symbols_document ON symbols(document_id);
    `);

    const tx = db.transaction(() => {
      for (const change of changedFiles) {
        if (change.status === "deleted") {
          deleteSymbolsForFile(db, change.path);
          filesDeleted++;
        } else if (change.status === "renamed" && change.oldPath) {
          renameFileInIndex(db, change.oldPath, change.path);
          filesAdded++;
        }
      }

      if (modifiedFiles.size > 0) {
        const symbols = parseScipForFiles(scipPath, modifiedFiles);
        const symbolsByFile: Record<string, ScipSymbol[]> = {};

        for (const sym of symbols) {
          if (sym.documentPath) {
            if (!symbolsByFile[sym.documentPath]) {
              symbolsByFile[sym.documentPath] = [];
            }
            symbolsByFile[sym.documentPath].push(sym);
          }
        }

        for (const [filePath, fileSymbols] of Object.entries(symbolsByFile)) {
          const count = upsertSymbolsForFile(db, filePath, fileSymbols);
          totalSymbols += count;
          filesAdded++;
        }
      }
    });

    tx();
    db.close();

    saveIndexRef(diffResult.toRef, projectPath);

    return {
      success: true,
      dbPath,
      filesChanged: changedFiles.length,
      filesDeleted,
      filesAdded,
      symbolCount: totalSymbols,
      fromRef: diffResult.fromRef,
      toRef: diffResult.toRef,
    };
  } catch (err) {
    db.close();
    const msg = err instanceof Error ? err.message : String(err);
    return { success: false, error: `incremental update failed: ${msg}` };
  }
}
