{"role":"user","content":[{"tool_use_id":"tool_yEz9VJr9gGirY5sSLXejQS3x","type":"tool_result","content":"     1→import { existsSync, statSync, readdirSync } from 'fs';
     2→import { join, resolve } from 'path';
     3→import { spawn } from 'child_process';
     4→
     5→export interface IndexState {
     6→  exists: boolean;
     7→  expired: boolean;
     8→  path: string | null;
     9→  ageMs: number | null;
    10→  reason?: string;
    11→}
    12→
    13→export interface MindKeeperConfig {
    14→  enabled: boolean;
    15→  indexDir: string;
    16→  maxAgeMs: number;
    17→  triggerOnEntry: boolean;
    18→  silent: boolean;
    19→}
    20→
    21→const DEFAULT_CONFIG: MindKeeperConfig = {
    22→  enabled: true,
    23→  indexDir: '.ai/mindkeeper',
    24→  maxAgeMs: 4 * 60 * 60 * 1000,
    25→  triggerOnEntry: true,
    26→  silent: false,
    27→};
    28→
    29→const INDEX_FILES = ['index.json', 'index.db', 'graph.json'];
    30→
    31→const SOURCE_EXTENSIONS = ['.ts', '.tsx', '.js', '.jsx', '.go', '.py', '.rs', '.java'];
    32→const SCAN_DIRS = ['src', 'lib', 'pkg', 'cmd', 'internal', 'app'];
    33→
    34→function findProjectRoot(startPath: string): string | null {
    35→  let dir = resolve(startPath);
    36→  const visited = new Set<string>();
    37→  while (!visited.has(dir)) {
    38→    visited.add(dir);
    39→    if (existsSync(join(dir, '.git'))) return dir;
    40→    if (existsSync(join(dir, '.ai'))) return dir;
    41→    const parent = join(dir, '..');
    42→    if (parent === dir) break;
    43→    dir = parent;
    44→  }
    45→  return null;
    46→}
    47→
    48→function getLatestSourceMtime(root: string): number {
    49→  let latest = 0;
    50→  const scanRoots: string[] = [];
    51→  for (const d of SCAN_DIRS) {
    52→    if (existsSync(join(root, d))) scanRoots.push(join(root, d));
    53→  }
    54→  if (scanRoots.length === 0) scanRoots.push(root);
    55→
    56→  for (const scanRoot of scanRoots) {
    57→    try {
    58→      const entries = readdirSync(scanRoot, { withFileTypes: true });
    59→      for (const entry of entries) {
    60→        if (entry.isDirectory()) {
    61→          if (entry.name === 'node_modules' || entry.name === '.git' || entry.name === 'dist' || entry.name === 'out') continue;
    62→          try {
    63→            const subEntries = readdirSync(join(scanRoot, entry.name), { withFileTypes: true });
    64→            for (const sub of subEntries) {
    65→              if (sub.isFile() && SOURCE_EXTENSIONS.some(ext => sub.name.endsWith(ext))) {
    66→                try {
    67→                  const stat = statSync(join(scanRoot, entry.name, sub.name));
    68→                  if (stat.mtimeMs > latest) latest = stat.mtimeMs;
    69→                } catch { /* skip unreadable files */ }
    70→              }
    71→            }
    72→          } catch { /* skip unreadable dirs */ }
    73→        } else if (entry.isFile() && SOURCE_EXTENSIONS.some(ext => entry.name.endsWith(ext))) {
    74→          try {
    75→            const stat = statSync(join(scanRoot, entry.name));
    76→            if (stat.mtimeMs > latest) latest = stat.mtimeMs;
    77→          } catch { /* skip */ }
    78→        }
    79→      }
    80→    } catch { /* skip unreadable roots */ }
    81→  }
    82→  return latest;
    83→}
    84→
    85→function probeIndexPath(root: string, config: MindKeeperConfig): string | null {
    86→  const base = join(root, config.indexDir);
    87→  if (!existsSync(base)) return null;
    88→  for (const name of INDEX_FILES) {
    89→    const candidate = join(base, name);
    90→    if (existsSync(candidate)) return candidate;
    91→  }
    92→  const entries = readdirSync(base).filter(f => !f.startsWith('.'));
    93→  if (entries.length > 0) return join(base, entries[0]);
    94→  return null;
    95→}
    96→
    97→export function checkIndexStatus(projectRoot: string, config?: Partial<MindKeeperConfig>): IndexState {
    98→  const cfg = { ...DEFAULT_CONFIG, ...config };
    99→  const root = projectRoot || findProjectRoot(process.cwd());
   100→  if (!root) return { exists: false, expired: false, path: null, ageMs: null };
   101→
   102→  const indexPath = probeIndexPath(root, cfg);
   103→  if (!indexPath) return { exists: false, expired: true, path: null, ageMs: null, reason: 'no_index_file' };
   104→
   105→  try {
   106→    const stat = statSync(indexPath);
   107→    const ageMs = Date.now() - stat.mtimeMs;
   108→
   109→    if (ageMs > cfg.maxAgeMs) {
   110→      return { exists: true, expired: true, path: indexPath, ageMs, reason: 'max_age_exceeded' };
   111→    }
   112→
   113→    const latestSrcMtime = getLatestSourceMtime(root);
   114→    if (latestSrcMtime > stat.mtimeMs) {
   115→      return { exists: true, expired: true, path: indexPath, ageMs, reason: 'source_files_modified' };
   116→    }
   117→
   118→    return { exists: true, expired: false, path: indexPath, ageMs };
   119→  } catch {
   120→    return { exists: false, expired: true, path: indexPath, ageMs: null, reason: 'stat_error' };
   121→  }
   122→}
   123→
   124→export function triggerFgIndex(projectRoot: string, config?: Partial<MindKeeperConfig>): boolean {
   125→  const cfg = { ...DEFAULT_CONFIG, ...config };
   126→  if (!cfg.enabled || !cfg.triggerOnEntry) return false;
   127→
   128→  const status = checkIndexStatus(projectRoot, cfg);
   129→  if (status.exists && !status.expired) return false;
   130→
   131→  const root = projectRoot || findProjectRoot(process.cwd());
   132→  if (!root) return false;
   133→
   134→  try {
   135→    const child = spawn('npx', ['fg-index'], {
   136→      cwd: root,
   137→      detached: true,
   138→      stdio: cfg.silent ? 'ignore' : 'inherit',
   139→    });
   140→    child.unref();
   141→    if (!cfg.silent) {
   142→      const reason = status.reason || 'unknown';
   143→      console.log(`[folder-graphy] Background index triggered (${reason}). PID: ${child.pid}`);
   144→    }
   145→    return true;
   146→  } catch {
   147→    if (!cfg.silent) {
   148→      console.warn('[folder-graphy] fg-index failed to spawn. Skipping auto-index.');
   149→    }
   150→    return false;
   151→  }
   152→}
   153→
   154→export function createConfig(overrides?: Partial<MindKeeperConfig>): MindKeeperConfig {
   155→  return { ...DEFAULT_CONFIG, ...overrides };
   156→}
   157→
   158→export { findProjectRoot, DEFAULT_CONFIG };
   159→

