{"type":"tool_use","id":"call_0e4e6f5de7d345eba667da3e","name":"Write","input":{"file_path":"/Users/xin/auto-skills/.claude/worktrees/worker-task-a-mnphisuy/domain-tool-core/lib/db.js","content":"const path = require('path');
const fs = require('fs');
const Database = require('better-sqlite3');

let db = null;
let dbPath = null;

function getDb(requestedDbPath) {
  const resolvedPath = path.resolve(requestedDbPath || 'data/graph.db');

  if (db && dbPath && dbPath !== resolvedPath) {
    throw new Error(`Database already open at "${dbPath}". Cannot open "${resolvedPath}" concurrently.`);
  }

  if (db) return db;

  const dir = path.dirname(resolvedPath);
  fs.mkdirSync(dir, { recursive: true });

  try {
    db = new Database(resolvedPath);
  } catch (err) {
    throw new Error(`Failed to open database at "${resolvedPath}": ${err.message}`);
  }

  dbPath = resolvedPath;

  const walResult = db.pragma('journal_mode = WAL');
  if (walResult[0] && walResult[0].journal_mode !== 'wal') {
    throw new Error('Failed to enable WAL journal mode');
  }

  const fkResult = db.pragma('foreign_keys = ON');
  if (fkResult[0] && fkResult[0].foreign_keys !== 1) {
    throw new Error('Failed to enable foreign keys');
  }

  initSchema(db);
  return db;
}

function initSchema(database) {
  const tableCheck = database.prepare(
    "SELECT name FROM sqlite_master WHERE type='table' AND name IN ('nodes', 'edges')"
  ).all();

  const hasNodes = tableCheck.some(r => r.name === 'nodes');
  const hasEdges = tableCheck.some(r => r.name === 'edges');

  if (!hasNodes) {
    database.exec(`
      CREATE TABLE nodes (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        type TEXT NOT NULL,
        name TEXT NOT NULL,
        file_path TEXT NOT NULL,
        start_line INTEGER,
        start_col INTEGER,
        UNIQUE(type, name, file_path, start_line, start_col)
      );
      CREATE INDEX idx_nodes_type ON nodes(type);
      CREATE INDEX idx_nodes_name ON nodes(name);
      CREATE INDEX idx_nodes_file ON nodes(file_path);
    `);
  }

  if (!hasEdges) {
    database.exec(`
      CREATE TABLE edges (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        from_node_id INTEGER NOT NULL REFERENCES nodes(id) ON DELETE CASCADE,
        to_node_id INTEGER NOT NULL REFERENCES nodes(id) ON DELETE CASCADE,
        relation_type TEXT NOT NULL CHECK(relation_type IN ('defines', 'imports', 'calls', 'references')),
