{"type":"tool_use","id":"tool_jHvYXfyxrB8Mse7t2m7JmjM4","name":"Write","input":{"file_path":"/Users/xin/auto-skills/.claude/worktrees/worker-task-c-mnphn4rf/src/db/scip-import.ts","content":"import Database from "better-sqlite3";
import { Index, SymbolInformation, SymbolRole, Relationship } from "../scip/types.js";
import { NodeType, EdgeKind } from "./schema.js";

export interface ImportOptions {
  batchSize?: number;
  skipDuplicates?: boolean;
  incremental?: boolean;
}

export interface ImportResult {
  nodesInserted: number;
  nodesUpdated: number;
  edgesInserted: number;
  duplicatesSkipped: number;
  errors: string[];
}

interface NodeInsert {
  type: NodeType;
  name: string;
  filePath: string;
  line: number | null;
  column: number | null;
  detail: string | null;
}

interface EdgeInsert {
  kind: EdgeKind;
  sourceSymbol: string;
  sourceFile: string;
  targetSymbol: string;
  targetFile: string;
  filePath: string;
  line: number | null;
  column: number | null;
}

export class ScipImporter {
  private db: Database.Database;
  private options: Required<ImportOptions>;

  constructor(db: Database.Database, options: ImportOptions = {}) {
    this.db = db;
    this.options = {
      batchSize: options.batchSize ?? 1000,
      skipDuplicates: options.skipDuplicates ?? true,
      incremental: options.incremental ?? true,
    };
  }

  importIndex(index: Index): ImportResult {
    const result: ImportResult = {
      nodesInserted: 0,
      nodesUpdated: 0,
      edgesInserted: 0,
      duplicatesSkipped: 0,
      errors: [],
    };

    const transaction = this.db.transaction(() => {
      const nodes = this.extractNodes(index);
      const { inserted, updated, skipped } = this.batchInsertNodes(nodes);
      result.nodesInserted = inserted;
      result.nodesUpdated = updated;
      result.duplicatesSkipped = skipped;

      const edges = this.extractEdges(index);
      result.edgesInserted = this.batchInsertEdges(edges);
    });

    try {
      transaction();
    } catch (err) {
      result.errors.push(`Transaction failed: ${err}`);
      throw err;
    }

    return result;
  }

  private extractNodes(index: Index): NodeInsert[] {
    const nodes: NodeInsert[] = [];
    const seen = new Set<string>();

    for (const doc of index.documents) {
      const fileNodeKey = `file:${doc.relativePath}`;
      if (!seen.has(fileNodeKey)) {
        seen.add(fileNodeKey);
        nodes.push({
          type: "file",
          name: doc.relativePath,
          filePath: doc.relativePath,
          line: null,
          column: null,
          detail: doc.language,
        });
      }

      for (const sym of doc.symbols) {
        const definitionOcc = doc.occurrences.find(
          (o) => o.symbol === sym.symbol && (o.symbolRoles & SymbolRole.Definition) !== 0
        );

        const nodeKey = `symbol:${sym.symbol}:${doc.relativePath}`;
        if (!seen.has(nodeKey)) {
          seen.add(nodeKey);
          nodes.push({
            type: "symbol",
            name: sym.displayName || sym.symbol,
            filePath: doc.relativePath,
            line: definitionOcc?.range.start.line ?? null,
            column: definitionOcc?.range.start.character ?? null,
            detail: sym.documentation?.join("\n") || null,
          });
        }
      }
    }

    for (const sym of index.externalSymbols || []) {
      const nodeKey = `symbol:${sym.symbol}:external`;
      if (!seen.has(nodeKey)) {
        seen.add(nodeKey);
        nodes.push({
          type: "symbol",
          name: sym.displayName || sym.symbol,
          filePath: "external",
          line: null,
          column: null,
          detail: sym.documentation?.join("\n") || null,
        });
      }
    }

    return nodes;
  }

  private batchInsertNodes(nodes: NodeInsert[]): { inserted: number; updated: number; skipped: number } {
    let inserted = 0;
    let updated = 0;
    let skipped = 0;

    const insertStmt = this.db.prepare(`
      INSERT INTO nodes (type, name, file_path, line, column, detail)
      VALUES (?, ?, ?, ?, ?, ?)
      ON CONFLICT(type, name, file_path) DO NOTHING
    `);

    const updateStmt = this.db.prepare(`
      UPDATE nodes
      SET line = ?, column = ?, detail = ?
      WHERE type = ? AND name = ? AND file_path = ?
    `);

    const selectStmt = this.db.prepare(`
      SELECT 1 FROM nodes WHERE type = ? AND name = ? AND file_path = ?
    `);

    for (let i = 0; i < nodes.length; i += this.options.batchSize) {
      const batch = nodes.slice(i, i + this.options.batchSize);

      const insertBatch = this.db.transaction((items: NodeInsert[]) => {
        for (const node of items) {
          if (this.options.incremental) {
            const exists = selectStmt.get(node.type, node.name, node.filePath);
            if (exists) {
              if (this.options.skipDuplicates) {
                skipped++;
                continue;
              }
              updateStmt.run(node.line, node.column, node.detail, node.type, node.name, node.filePath);
              updated++;
              continue;
            }
          }

          const result = insertStmt.run(
            node.type,
            node.name,
            node.filePath,
            node.line,
            node.column,
            node.detail
          );
          if (result.changes > 0) {
            inserted++;
          } else {
            skipped++;
          }
        }
      });

      insertBatch(batch);
    }

    return { inserted, updated, skipped };
  }

  private extractEdges(index: Index): EdgeInsert[] {
    const edges: EdgeInsert[] = [];

    for (const doc of index.documents) {
      for (const sym of doc.symbols) {
        const sourceFile = doc.relativePath;

        for (const rel of sym.relationships || []) {
          const edge = this.createEdgeFromRelationship(rel, sym.symbol, sourceFile, doc);
          if (edge) {
            edges.push(edge);
          }
        }
      }

      for (const occ of doc.occurrences) {
        if ((occ.symbolRoles & SymbolRole.Definition) !== 0) continue;

        const targetFile = this.findSymbolFile(index, occ.symbol);
        edges.push({
          kind: "references",
          sourceSymbol: occ.symbol,
          sourceFile: doc.relativePath,
          targetSymbol: occ.symbol,
          targetFile: targetFile || "external",
          filePath: doc.relativePath,
          line: occ.range.start.line,
          column: occ.range.start.character,
        });
      }
    }

    return edges;
  }

  private createEdgeFromRelationship(
    rel: Relationship,
    sourceSymbol: string,
    sourceFile: string,
    doc: { relativePath: string; occurrences: { symbol: string; range: { start: { line: number; character: number } }; symbolRoles: number }[] }
  ): EdgeInsert | null {
    let kind: EdgeKind;
    if (rel.isImplementation) {
      kind = "defines";
    } else if (rel.isReference) {
      kind = "references";
    } else {
      kind = "calls";
    }

    const occ = doc.occurrences.find((o) => o.symbol === sourceSymbol);

    return {
      kind,
      sourceSymbol,
      sourceFile,
      targetSymbol: rel.symbol,
      targetFile: "external",
      filePath: sourceFile,
      line: occ?.range.start.line ?? null,
      column: occ?.range.start.character ?? null,
    };
  }

  private findSymbolFile(index: Index, symbol: string): string | null {
    for (const doc of index.documents) {
      for (const sym of doc.symbols) {
        if (sym.symbol === symbol) {
          return doc.relativePath;
        }
      }
    }
    return null;
  }

  private batchInsertEdges(edges: EdgeInsert[]): number {
    let inserted = 0;

    const insertStmt = this.db.prepare(`
      INSERT INTO edges (kind, source_id, target_id, file_path, line, column)
      SELECT ?, n1.id, n2.id, ?, ?, ?
      FROM nodes n1, nodes n2
      WHERE n1.name = ? AND n1.file_path = ?
        AND n2.name = ? AND n2.file_path = ?
      ON CONFLICT DO NOTHING
    `);

    for (let i = 0; i < edges.length; i += this.options.batchSize) {
      const batch = edges.slice(i, i + this.options.batchSize);

      const insertBatch = this.db.transaction((items: EdgeInsert[]) => {
        for (const edge of items) {
          const result = insertStmt.run(
            edge.kind,
            edge.filePath,
            edge.line,
            edge.column,
            edge.sourceSymbol,
            edge.sourceFile,
            edge.targetSymbol,
            edge.targetFile
          );
          if (result.changes > 0) {
            inserted++;
          }
        }
      });

      insertBatch(batch);
    }

    return inserted;
  }
}

export function importScipIndex(
  db: Database.Database,
  index: Index,
  options?: ImportOptions
): ImportResult {
  const importer = new ScipImporter(db, options);
  return importer.importIndex(index);
}
