{"type":"tool_use","id":"tool_izal8rLOoeB9kOtpm21KPQo5","name":"Write","input":{"file_path":"/Users/xin/auto-skills/.claude/worktrees/worker-task-c-mnphn4rf/src/cli/fg-import.ts","content":"#!/usr/bin/env node
import { resolve, basename } from "path";
import { existsSync } from "fs";
import Database from "better-sqlite3";
import { parseIndex } from "../scip/parser.js";
import { initSchema } from "../db/schema.js";
import { importScipIndex, ImportOptions, ImportResult } from "../db/scip-import.js";

interface CliArgs {
  input: string;
  output: string;
  batchSize: number;
  skipDuplicates: boolean;
  incremental: boolean;
  help: boolean;
}

function parseArgs(argv: string[]): CliArgs {
  const args: CliArgs = {
    input: "",
    output: "",
    batchSize: 1000,
    skipDuplicates: true,
    incremental: true,
    help: false,
  };

  for (let i = 2; i < argv.length; i++) {
    const flag = argv[i];
    if (flag === "--input" || flag === "-i") {
      args.input = argv[++i];
    } else if (flag === "--output" || flag === "-o") {
      args.output = argv[++i];
    } else if (flag === "--batch-size" || flag === "-b") {
      args.batchSize = parseInt(argv[++i], 10);
    } else if (flag === "--no-skip-duplicates") {
      args.skipDuplicates = false;
    } else if (flag === "--no-incremental") {
      args.incremental = false;
    } else if (flag === "--help" || flag === "-h") {
      args.help = true;
    } else {
      console.error(`Unknown argument: ${flag}`);
      process.exit(1);
    }
  }

  return args;
}

function printUsage(): void {
  console.log("Usage: fg-import --input <scip-file> --output <db-file> [options]");
  console.log("");
  console.log("Options:");
  console.log("  --input, -i          Path to SCIP JSON file (required)");
  console.log("  --output, -o         Path to SQLite database (required)");
  console.log("  --batch-size, -b     Batch size for inserts (default: 1000)");
  console.log("  --no-skip-duplicates Update existing records instead of skipping");
  console.log("  --no-incremental     Disable incremental update mode");
  console.log("  --help, -h           Show this help message");
  console.log("");
  console.log("Imports SCIP index data into SQLite with transaction support.");
  console.log("Handles duplicate symbols via UPSERT logic.");
}

function formatNumber(n: number): string {
  return n.toLocaleString();
}

function printResult(result: ImportResult, durationMs: number): void {
  console.log("\n✓ Import completed successfully");
  console.log("");
  console.log("Statistics:");
  console.log(`  Nodes inserted:  ${formatNumber(result.nodesInserted)}`);
  console.log(`  Nodes updated:   ${formatNumber(result.nodesUpdated)}`);
  console.log(`  Edges inserted:  ${formatNumber(result.edgesInserted)}`);
  console.log(`  Duplicates skipped: ${formatNumber(result.duplicatesSkipped)}`);
  console.log(`  Duration:        ${durationMs}ms`);

  if (result.errors.length > 0) {
    console.log("\nErrors:");
    for (const err of result.errors) {
      console.log(`  - ${err}`);
    }
  }
}

async function main(): Promise<void> {
  const args = parseArgs(process.argv);

  if (args.help) {
    printUsage();
    process.exit(0);
  }

  if (!args.input) {
    console.error("Error: --input is required");
    printUsage();
    process.exit(1);
  }

  if (!args.output) {
    console.error("Error: --output is required");
    printUsage();
    process.exit(1);
  }

  const inputPath = resolve(args.input);
  const outputPath = resolve(args.output);

  if (!existsSync(inputPath)) {
    console.error(`Error: input file does not exist: ${inputPath}`);
    process.exit(1);
  }

  console.log(`Importing SCIP index: ${basename(inputPath)}`);
  console.log(`Target database: ${outputPath}`);
  console.log(`Batch size: ${args.batchSize}`);
  console.log("");

  const startTime = Date.now();

  try {
    console.log("Parsing SCIP index...");
    const parseResult = parseIndex(inputPath);

    console.log(`Found ${formatNumber(parseResult.index.documents.length)} documents`);
    console.log(`Found ${formatNumber(parseResult.symbols.length)} symbols`);
    console.log("");

    console.log("Initializing database...");
    const db = new Database(outputPath);
    db.pragma("journal_mode = WAL");
    initSchema(db);

    const options: ImportOptions = {
      batchSize: args.batchSize,
      skipDuplicates: args.skipDuplicates,
      incremental: args.incremental,
    };

    console.log("Importing data (with transaction)...");
    const result = importScipIndex(db, parseResult.index, options);

    const duration = Date.now() - startTime;
    printResult(result, duration);

    db.close();
    process.exit(0);
  } catch (err) {
    console.error("\n✗ Import failed:");
    console.error(err instanceof Error ? err.message : String(err));
    process.exit(1);
