import { resolve } from "path";
import { existsSync } from "fs";
import { detectLanguages, buildIndex, IndexResult } from "../indexer/builder.js";

interface CliArgs {
  projectDir: string;
  help: boolean;
}

function parseArgs(argv: string[]): CliArgs {
  const args: CliArgs = { projectDir: process.cwd(), help: false };
  for (let i = 2; i < argv.length; i++) {
    const flag = argv[i];
    if (flag === "--project-dir") {
      args.projectDir = argv[++i];
    } else if (flag === "--help" || flag === "-h") {
      args.help = true;
    } else {
      console.error(`Unknown argument: ${flag}`);
      process.exit(1);
    }
  }
  return args;
}

function printUsage(): void {
  console.log("Usage: fg-index --project-dir <path>");
  console.log("");
  console.log("Options:");
  console.log("  --project-dir  Path to the project root (default: cwd)");
  console.log("  --help, -h     Show this help message");
  console.log("");
  console.log("Automatically detects TypeScript and Go files,");
  console.log("runs the appropriate SCIP indexer, and writes results to SQLite.");
}

async function main(): Promise<void> {
  const args = parseArgs(process.argv);

  if (args.help) {
    printUsage();
    process.exit(0);
  }

  const projectPath = resolve(args.projectDir);
  if (!existsSync(projectPath)) {
    console.error(`Error: project path does not exist: ${projectPath}`);
    process.exit(1);
  }

  const languages = detectLanguages(projectPath);
  if (languages.length === 0) {
    console.error(`Error: no supported languages detected in ${projectPath}`);
    console.error("Supported: typescript (.ts/.tsx), go (.go)");
    process.exit(1);
  }

  console.log(`Detected languages: ${languages.join(", ")}`);
  console.log(`Project path: ${projectPath}`);

  for (const lang of languages) {
    console.log(`\nIndexing ${lang}...`);
    const result: IndexResult = await buildIndex(projectPath, lang);

    if (result.success) {
      console.log(
        `  DB: ${result.dbPath} | Documents: ${result.documentCount} | Symbols: ${result.symbolCount}`
      );
    } else {
      console.error(`  Indexing ${lang} failed: ${result.error}`);
      process.exit(1);
    }
  }
}

main().catch((err) => {
  console.error("Unexpected error:", err);
  process.exit(1);
});
