import { join, basename, extname } from "path";
import { execFile } from "child_process";
import { promisify } from "util";
import Database from "better-sqlite3";
import { parseIndex } from "../scip/parser.js";
import { SymbolKind, SymbolRole } from "../scip/types.js";
import { initSchema } from "../db/schema.js";

const execFileAsync = promisify(execFile);

export type ProjectLanguage = "typescript" | "go";

export interface IndexResult {
  success: boolean;
  dbPath?: string;
  documentCount?: number;
  symbolCount?: number;
  error?: string;
}

const TS_EXTENSIONS = new Set([".ts", ".tsx"]);
const GO_EXTENSIONS = new Set([".go"]);

function hasFilesWithExt(dir: string, exts: Set<string>, depth: number): boolean {
  if (depth > 3) return false;
  const entries = readdirSync(dir, { withFileTypes: true });
  for (const entry of entries) {
    if (entry.name.startsWith(".") || entry.name === "node_modules" || entry.name === "dist") {
      continue;
    }
    const full = join(dir, entry.name);
    if (entry.isFile()) {
      if (exts.has(extname(entry.name))) return true;
    } else if (entry.isDirectory()) {
      if (hasFilesWithExt(full, exts, depth + 1)) return true;
    }
  }
  return false;
}

export function detectLanguages(projectPath: string): ProjectLanguage[] {
  const languages: ProjectLanguage[] = [];
  if (
    existsSync(join(projectPath, "tsconfig.json")) ||
    hasFilesWithExt(projectPath, TS_EXTENSIONS, 0)
  ) {
    languages.push("typescript");
  }
  if (
    existsSync(join(projectPath, "go.mod")) ||
    hasFilesWithExt(projectPath, GO_EXTENSIONS, 0)
  ) {
    languages.push("go");
  }
  return languages;
}

function indexerCommand(
  language: ProjectLanguage
): { cmd: string; args: string[] } | null {
  switch (language) {
    case "typescript":
      return { cmd: "scip-typescript", args: ["index", "--output", "index.scip"] };
    case "go":
      return { cmd: "scip-go", args: ["index", "--output", "index.scip"] };
    default:
      return null;
  }
}

function importToDb(
  db: Database.Database,
  projectPath: string
): { documentCount: number; symbolCount: number } {
  const scipPath = join(projectPath, "index.scip");
  const { symbols } = parseIndex(scipPath);

  const insertNode = db.prepare(`
    INSERT OR IGNORE INTO nodes (type, name, file_path, line, column, detail)
    VALUES (?, ?, ?, ?, ?, ?)
  `);
  const findNode = db.prepare(`
    SELECT id FROM nodes WHERE type = ? AND name = ? AND file_path = ?
  `);
  const insertEdge = db.prepare(`
    INSERT INTO edges (kind, source_id, target_id, file_path, line, column)
    VALUES (?, ?, ?, ?, ?, ?)
  `);

  const filePaths = new Set<string>();
  const symIds = new Map<string, number>();

  const tx = db.transaction(() => {
    for (const sym of symbols) {
      filePaths.add(sym.filePath);
      const line = sym.position.line + 1;
      const column = sym.position.character + 1;
      const kindName = SymbolKind[sym.kind] ?? "Unknown";
      insertNode.run(
        "symbol",
        sym.symbol,
        sym.filePath,
        line,
        column,
        `${kindName}: ${sym.displayName}`
      );
      const row = findNode.get("symbol", sym.symbol, sym.filePath) as {
        id: number;
      } | undefined;
      if (row) symIds.set(sym.symbol, row.id);
    }

    for (const fp of filePaths) {
      insertNode.run("file", fp, fp, null, null, null);
    }

    let edgeCount = 0;
    const allSymbols = [...symIds.entries()];
    for (let i = 0; i < allSymbols.length; i++) {
      for (let j = i + 1; j < allSymbols.length; j++) {
        if (allSymbols[i][1] === allSymbols[j][1]) continue;
        const [sym1] = allSymbols[i];
        const [sym2] = allSymbols[j];
        const sym1Data = symbols.find((s) => s.symbol === sym1);
        const sym2Data = symbols.find((s) => s.symbol === sym2);
        if (!sym1Data || !sym2Data) continue;

        if (sym1Data.filePath === sym2Data.filePath) {
          insertEdge.run(
            "references",
            allSymbols[i][1],
            allSymbols[j][1],
            sym1Data.filePath,
            sym1Data.position.line + 1,
            sym1Data.position.character + 1
          );
          edgeCount++;
        }
      }
    }

    return { documentCount: filePaths.size, symbolCount: symbols.length };
  });

  return tx();
}

export async function buildIndex(
  projectPath: string,
  language: ProjectLanguage
): Promise<IndexResult> {
  const spec = indexerCommand(language);
  if (!spec) {
    return { success: false, error: `unsupported language: ${language}` };
  }

  try {
    await execFileAsync(spec.cmd, spec.args, { cwd: projectPath });
  } catch (err) {
    const msg = err instanceof Error ? err.message : String(err);
    return { success: false, error: `indexer failed: ${msg}` };
  }

  const scipPath = join(projectPath, "index.scip");
  if (!existsSync(scipPath)) {
    return {
      success: false,
      error: `indexer produced no output at ${scipPath}`,
    };
  }

  const dbPath = join(projectPath, `${basename(projectPath)}.fg-index.db`);

  const db = new Database(dbPath);
  try {
    initSchema(db);
    const counts = importToDb(db, projectPath);
    db.close();

    return {
      success: true,
      dbPath,
      documentCount: counts.documentCount,
      symbolCount: counts.symbolCount,
    };
  } catch (err) {
    db.close();
    const msg = err instanceof Error ? err.message : String(err);
    return { success: false, error: `sqlite write failed: ${msg}` };
  }
}
