{"type":"tool_use","id":"call_9f210bf6131947679d9a74db","name":"Write","input":{"file_path":"/Users/xin/auto-skills/.claude/worktrees/worker-task-f-mnphx6pd/src/query/engine.ts","content":"import { execSync } from "child_process";
import Database from "better-sqlite3";
import { join } from "path";
import { existsSync } from "fs";

export interface QueryResult {
  file: string;
  line: number;
  column: number;
  text: string;
  kind: "definition" | "reference" | "call";
}

export interface QueryOptions {
  cwd?: string;
  dbPath?: string;
}

function findDbPath(cwd: string): string | null {
  const name = cwd.split("/").pop() || "project";
  const candidates = [
    join(cwd, `${name}.fg-index.db`),
    join(cwd, ".ai", "mindkeeper", "index.db"),
    join(cwd, "index.db"),
  ];
  for (const p of candidates) {
    if (existsSync(p)) return p;
  }
  return null;
}

function rgAvailable(): boolean {
  try {
    execSync("rg --version", { stdio: "pipe" });
    return true;
  } catch {
    return false;
  }
}

function escapeRegex(s: string): string {
  return s.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

function shellQuote(s: string): string {
  return `'${s.replace(/'/g, "'\\''")}'`;
}

export function findDefinition(symbol: string, options: QueryOptions = {}): QueryResult[] {
  const cwd = options.cwd || process.cwd();
  const dbPath = options.dbPath || findDbPath(cwd);

  if (dbPath) {
    try {
      const db = new Database(dbPath);
      const stmt = db.prepare(
        `SELECT s.name, s.definition, s.kind
         FROM symbols s
         WHERE s.name LIKE ? AND s.definition IS NOT NULL`
      );
      const rows = stmt.all(`%${symbol}%`) as Array<{ name: string; definition: string; kind: string }>;
      db.close();

      const results: QueryResult[] = [];
      for (const r of rows) {
        const parts = r.definition?.split(":");
        if (!parts || parts.length < 2) continue;
        results.push({
          file: parts[0],
          line: parseInt(parts[1], 10) || 0,
          column: 0,
          text: `${r.kind}: ${r.name}`,
          kind: "definition",
        });
      }
      return results;
    } catch {
      // Fall through to grep
    }
  }

  const escaped = escapeRegex(symbol);
  let cmd: string;
  if (rgAvailable()) {
    cmd = [
      "rg", "-n", "--no-heading", "-g", "*.{ts,tsx,js,jsx}",
      shellQuote(`^(export\\s+)?(async\\s+)?(function|const|let|class|interface|type|enum)\\s+${escaped}\\b`),
    ].join(" ");
  } else {
    cmd = `grep -rn ${shellQuote(`${escaped}`)} --include='*.ts' --include='*.tsx' --include='*.js'`;
  }

  try {
    const output = execSync(cmd, { cwd, encoding: "utf-8", maxBuffer: 10 * 1024 * 1024 });
    return parseGrepOutput(output).map((r) => ({ ...r, kind: "definition" as const }));
  } catch {
    return [];
  }
}

export function findReferences(symbol: string, options: QueryOptions = {}): QueryResult[] {
  const cwd = options.cwd || process.cwd();
  const escaped = escapeRegex(symbol);

  let cmd: string;
  if (rgAvailable()) {
    cmd = [
      "rg", "-n", "--no-heading", "-g", "*.{ts,tsx,js,jsx}",
      shellQuote(`\\b${escaped}\\b`),
    ].join(" ");
  } else {
    cmd = `grep -rn ${shellQuote(escaped)} --include='*.ts' --include='*.tsx' --include='*.js'`;
  }

  try {
    const output = execSync(cmd, { cwd, encoding: "utf-8", maxBuffer: 10 * 1024 * 1024 });
    return parseGrepOutput(output).map((r) => ({ ...r, kind: "reference" as const }));
  } catch {
    return [];
  }
}

export function findCallers(symbol: string, options: QueryOptions = {}): QueryResult[] {
  const cwd = options.cwd || process.cwd();
  const escaped = escapeRegex(symbol);

  let cmd: string;
  if (rgAvailable()) {
    cmd = [
      "rg", "-n", "--no-heading", "-g", "*.{ts,tsx,js,jsx}",
      shellQuote(`${escaped}\\s*\\(`),
    ].join(" ");
  } else {
    cmd = `grep -rn ${shellQuote(escaped)} --include='*.ts' --include='*.tsx' --include='*.js'`;
  }

  try {
    const output = execSync(cmd, { cwd, encoding: "utf-8", maxBuffer: 10 * 1024 * 1024 });
    return parseGrepOutput(output).map((r) => ({ ...r, kind: "call" as const }));
  } catch {
    return [];
  }
}

function parseGrepOutput(output: string): Array<{ file: string; line: number; column: number; text: string }> {
  if (!output.trim()) return [];
  const results: Array<{ file: string; line: number; column: number; text: string }> = [];
  for (const raw of output.trim().split("\n")) {
    // rg format: /path/file:line:col:text  or  /path/file:line:col:text (col may be absent for grep)
    // Use last three colon-separated segments for line:col:text, everything before is the file path
    const lastColon = raw.lastIndexOf(":");
    if (lastColon === -1) continue;
    const text = raw.slice(lastColon + 1).trim();
    const rest = raw.slice(0, lastColon);

    const secondLast = rest.lastIndexOf(":");
    if (secondLast === -1) continue;
    const colOrText = rest.slice(secondLast + 1);

    const beforeSecond = rest.slice(0, secondLast);
    const thirdLast = beforeSecond.lastIndexOf(":");

    let file: string;
    let line: number;
    let column: number;

    if (thirdLast !== -1) {
      file = beforeSecond.slice(0, thirdLast);
      line = parseInt(beforeSecond.slice(thirdLast + 1), 10);
      column = parseInt(colOrText, 10) || 0;
    } else {
      file = beforeSecond;
      line = parseInt(colOrText, 10);
      column = 0;
    }

    if (!file || isNaN(line)) continue;
    results.push({ file, line, column, text });
  }
  return results;
}
